import { page, render } from "#test/browser"
import { ClientOnly } from "."

describe("<ClientOnly />", () => {
  test("renders children after mount", async () => {
    await render(<ClientOnly>Hello</ClientOnly>)

    await expect.element(page.getByText("Hello")).toBeInTheDocument()
  })

  test("renders fallback when provided", async () => {
    await render(
      <ClientOnly fallback={<span>Loading...</span>}>Hello</ClientOnly>,
    )

    await expect.element(page.getByText("Hello")).toBeInTheDocument()
  })

  test("supports function children", async () => {
    await render(<ClientOnly>{() => "Hello from function"}</ClientOnly>)

    await expect
      .element(page.getByText("Hello from function"))
      .toBeInTheDocument()
  })
})

"use client"

import type { FC, ReactNode } from "react"
import type { ReactNodeOrFunction } from "@yamada-ui/react"
import { useMounted } from "../../hooks/use-mounted"
import { Show } from "../show"

export interface ClientOnlyProps {
  /**
   * The content to render on the client side.
   *
   * **Note:** Use the function pattern when accessing browser-only APIs.
   */
  children: ReactNodeOrFunction
  /**
   * The fallback content to render while the component is mounting on the client
   * side.
   */
  fallback?: ReactNode
}

/**
 * `ClientOnly` is a component that renders its children only on the client side.
 *
 * @see https://yamada-ui.com/docs/components/client-only
 */
export const ClientOnly: FC<ClientOnlyProps> = ({ children, fallback }) => {
  const mounted = useMounted({ state: true })

  return (
    <Show fallback={fallback} when={mounted}>
      {children}
    </Show>
  )
}
